/**
 * Webhook notification adapter.
 *
 * Sends notifications via HTTP POST to a configured URL with a JSON payload.
 * Implements NotificationAdapter so it can be registered with
 * NotificationService.registerAdapter().
 *
 * Features:
 * - Configurable webhook URL and optional secret for authentication
 * - Formats NotificationPayload as a structured JSON body
 * - Validates the webhook URL before sending
 * - Tracks delivered webhooks in memory for testing/audit
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret included as an X-Webhook-Secret header for authentication. */
  secret?: string;
}

/**
 * Represents a formatted webhook delivery ready for sending.
 */
export interface WebhookDelivery {
  url: string;
  headers: Record<string, string>;
  body: WebhookBody;
}

/**
 * The JSON body sent in the webhook POST request.
 */
export interface WebhookBody {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, string>;
  timestamp: string;
}

/**
 * Validates that a string is a well-formed HTTP(S) URL.
 */
function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];

  constructor(private config: WebhookConfig) {
    if (!isValidUrl(config.url)) {
      throw new Error(`Invalid webhook URL: "${config.url}"`);
    }
  }

  /**
   * Format a NotificationPayload into a WebhookDelivery containing the
   * URL, headers, and JSON body to POST.
   */
  formatDelivery(payload: NotificationPayload): WebhookDelivery {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    if (this.config.secret) {
      headers['X-Webhook-Secret'] = this.config.secret;
    }

    const body: WebhookBody = {
      event: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      timestamp: new Date().toISOString(),
    };

    if (payload.metadata && Object.keys(payload.metadata).length > 0) {
      body.metadata = payload.metadata;
    }

    return {
      url: this.config.url,
      headers,
      body,
    };
  }

  /**
   * Send a webhook notification.
   *
   * Formats the payload as JSON and POSTs it to the configured URL.
   * In production this would use fetch/http; currently stores the
   * delivery in memory.
   */
  async send(payload: NotificationPayload): Promise<void> {
    const delivery = this.formatDelivery(payload);

    this.logger.info(
      `Posting webhook to ${delivery.url}: ${payload.type} for ${payload.recipient}`,
    );

    // In production, this is where we'd POST to the URL.
    // e.g., await fetch(delivery.url, { method: 'POST', headers: delivery.headers, body: JSON.stringify(delivery.body) });
    this.deliveries.push(delivery);
  }

  /**
   * Get all delivered webhooks. Useful for testing.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Clear delivery history. Useful for testing.
   */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

