import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  const defaultUrl = 'https://hooks.example.com/notify';

  beforeEach(() => {
    adapter = new WebhookAdapter({ url: defaultUrl });
  });

  describe('channel', () => {
    it('should report webhook channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('constructor', () => {
    it('should accept a valid HTTPS URL', () => {
      expect(() => new WebhookAdapter({ url: 'https://example.com/hook' })).not.toThrow();
    });

    it('should accept a valid HTTP URL', () => {
      expect(() => new WebhookAdapter({ url: 'http://localhost:3000/hook' })).not.toThrow();
    });

    it('should throw for an invalid URL', () => {
      expect(() => new WebhookAdapter({ url: 'not-a-url' })).toThrow('Invalid webhook URL');
    });

    it('should throw for an empty URL', () => {
      expect(() => new WebhookAdapter({ url: '' })).toThrow('Invalid webhook URL');
    });

    it('should throw for a non-HTTP protocol', () => {
      expect(() => new WebhookAdapter({ url: 'ftp://example.com/hook' })).toThrow('Invalid webhook URL');
    });
  });

  describe('formatDelivery', () => {
    const basePayload: NotificationPayload = {
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
      channel: 'webhook',
      type: 'order:confirmation',
    };

    it('should format payload into a webhook delivery with correct URL', () => {
      const delivery = adapter.formatDelivery(basePayload);
      expect(delivery.url).toBe(defaultUrl);
    });

    it('should include Content-Type header', () => {
      const delivery = adapter.formatDelivery(basePayload);
      expect(delivery.headers['Content-Type']).toBe('application/json');
    });

    it('should not include X-Webhook-Secret when no secret is configured', () => {
      const delivery = adapter.formatDelivery(basePayload);
      expect(delivery.headers['X-Webhook-Secret']).toBeUndefined();
    });

    it('should include X-Webhook-Secret when secret is configured', () => {
      const secretAdapter = new WebhookAdapter({ url: defaultUrl, secret: 'my-secret-key' });
      const delivery = secretAdapter.formatDelivery(basePayload);
      expect(delivery.headers['X-Webhook-Secret']).toBe('my-secret-key');
    });

    it('should map notification type to event field', () => {
      const delivery = adapter.formatDelivery(basePayload);
      expect(delivery.body.event).toBe('order:confirmation');
    });

    it('should include recipient, subject, and body', () => {
      const delivery = adapter.formatDelivery(basePayload);
      expect(delivery.body.recipient).toBe('alice@example.com');
      expect(delivery.body.subject).toBe('Order Confirmation: order-1');
      expect(delivery.body.body).toBe('Your order has been placed. Items: Widget x2. Total: $20.00');
    });

    it('should include a timestamp in ISO format', () => {
      const delivery = adapter.formatDelivery(basePayload);
      expect(delivery.body.timestamp).toBeDefined();
      expect(new Date(delivery.body.timestamp).toISOString()).toBe(delivery.body.timestamp);
    });

    it('should include metadata when present', () => {
      const payload: NotificationPayload = {
        ...basePayload,
        metadata: { orderId: 'order-1', priority: 'high' },
      };
      const delivery = adapter.formatDelivery(payload);
      expect(delivery.body.metadata).toEqual({ orderId: 'order-1', priority: 'high' });
    });

    it('should omit metadata when not present', () => {
      const delivery = adapter.formatDelivery(basePayload);
      expect(delivery.body.metadata).toBeUndefined();
    });

    it('should format all notification types correctly', () => {
      const types = [
        'order:confirmation',
        'order:status-update',
        'user:welcome',
        'user:profile-updated',
      ] as const;

      for (const type of types) {
        const payload: NotificationPayload = { ...basePayload, type };
        const delivery = adapter.formatDelivery(payload);
        expect(delivery.body.event).toBe(type);
      }
    });
  });

  describe('send', () => {
    it('should store delivery on send', async () => {
      const payload: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        channel: 'webhook',
        type: 'order:confirmation',
      };

      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe(defaultUrl);
      expect(deliveries[0]?.body.event).toBe('order:confirmation');
      expect(deliveries[0]?.body.recipient).toBe('alice@example.com');
    });

    it('should accumulate multiple deliveries', async () => {
      const payload1: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Webhook 1',
        body: 'First webhook',
        channel: 'webhook',
        type: 'order:confirmation',
      };
      const payload2: NotificationPayload = {
        recipient: 'bob@example.com',
        subject: 'Webhook 2',
        body: 'Second webhook',
        channel: 'webhook',
        type: 'order:status-update',
      };

      await adapter.send(payload1);
      await adapter.send(payload2);

      expect(adapter.getDeliveries()).toHaveLength(2);
    });
  });

  describe('getDeliveries / clearDeliveries', () => {
    it('should return empty array initially', () => {
      expect(adapter.getDeliveries()).toEqual([]);
    });

    it('should return a copy (not the internal array)', async () => {
      await adapter.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        channel: 'webhook',
        type: 'order:confirmation',
      });

      const first = adapter.getDeliveries();
      const second = adapter.getDeliveries();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear all deliveries', async () => {
      await adapter.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        channel: 'webhook',
        type: 'order:confirmation',
      });

      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });
  });
});

